// Reference dataset types — the single source of truth shared by the website
// reference pages (web) and the kapi-desktop Storybook fixtures.
//
// The dataset documents (formats.json / tools.json / commands.json) are
// generated by scripts/gen-refs (Go). The schema/doc types an entry carries are
// re-exported from the shared @neokapi/contract-types package (issue #817), so a
// dataset entry's `schema` is assignable to SchemaForm's `schema` prop and
// `doc.parameters` to `paramDocs` without a hand-maintained mirror.

// ── Schema-form types (re-exported from @neokapi/contract-types) ──
export type {
  ComponentSchema,
  FormatMeta,
  ToolMeta,
  ParameterGroup,
  ConditionExpr,
  LayoutHints,
  PropertySchema,
  ToolDocParam,
} from "@neokapi/contract-types";

import type { ComponentSchema, ToolDocParam } from "@neokapi/contract-types";

// ── Reference dataset types ─────────────────────────────────────────────────

/** Which engine provides an entry. */
export type ReferenceSource = "built-in" | "okapi";

/** Whether an entry is a data format or a processing tool. */
export type ReferenceKind = "format" | "tool";

/** A worked configuration example. */
export interface ReferenceExample {
  title: string;
  description?: string;
  /** Fenced YAML configuration snippet. */
  config?: string;
  input?: string;
  output?: string;
}

/** Rich reference documentation for an entry. `parameters` is handed to
 *  SchemaForm as its `paramDocs` prop unchanged. */
export interface ReferenceDoc {
  overview?: string;
  parameters?: Record<string, ToolDocParam>;
  limitations?: string[];
  processingNotes?: string[];
  examples?: ReferenceExample[];
  wikiUrl?: string;
}

/** One format or tool in the reference dataset. */
export interface ReferenceEntry {
  id: string;
  source: ReferenceSource;
  kind: ReferenceKind;
  displayName: string;
  description?: string;

  // Format-only metadata.
  extensions?: string[];
  mimeTypes?: string[];
  hasReader?: boolean;
  hasWriter?: boolean;

  // Tool-only metadata.
  category?: string;
  inputs?: string[];
  outputs?: string[];
  tags?: string[];
  requires?: string[];
  cardinality?: string;
  /** IO contract ports as "type@side" tokens (consumed ports add a trailing "?" when optional). */
  consumes?: string[];
  produces?: string[];
  /** External systems the tool reads/writes (e.g. "tm-read", "api-call"). */
  sideEffects?: string[];
  /** Whether the tool is a transformer — it may rewrite the source (CapTransform). */
  isSourceTransform?: boolean;
  /** A recoverable transformer (redaction) vaults originals and restores them later. */
  recoverable?: boolean;
  aliases?: string[];

  /** The schema consumed verbatim by the shared SchemaForm renderer. */
  schema?: ComponentSchema;
  doc?: ReferenceDoc;
  presets?: Record<string, Record<string, unknown>>;
}

/** Top-level document for formats.json / tools.json. */
export interface ReferenceDataset {
  generatedAt: string;
  kind: ReferenceKind;
  entries: ReferenceEntry[];
}

/** One missing-metadata finding. */
export interface ReferenceGap {
  kind: ReferenceKind;
  source: ReferenceSource;
  id: string;
  field: string;
  detail: string;
}

/** Top-level document for reference-gaps.json. */
export interface ReferenceGapReport {
  generatedAt: string;
  summary: Record<string, number>;
  gaps: ReferenceGap[];
}

// ── Command reference types ─────────────────────────────────────────────────

/** One flag on a CLI command. */
export interface CommandFlag {
  /** Long flag name (without --). */
  name: string;
  /** Single-character shorthand (without -). Absent when not set. */
  shorthand?: string;
  /** Human-readable usage description. */
  usage?: string;
  /** Default value as a string (empty string when the default is ""). */
  default?: string;
  /** Go pflag value type, e.g. "string", "bool", "int", "stringSlice". */
  type?: string;
}

/** One command or subcommand in the kapi CLI. */
export interface CommandEntry {
  /**
   * Dot-joined command path, e.g. "formats.info".
   * Top-level commands have a single segment, e.g. "pseudo-translate".
   */
  id: string;
  /**
   * Ordered list of command name segments (root "kapi" is excluded),
   * e.g. ["formats", "info"].
   */
  path: string[];
  /** Cobra Use string, e.g. "info <format>". */
  use: string;
  /** One-line description. */
  short?: string;
  /** Multi-line description. */
  long?: string;
  /** Alternative command names. */
  aliases?: string[];
  /** Cobra command group ID, e.g. "processing", "management". */
  groupID?: string;
  /** Local flags registered on this command (excludes inherited persistent flags). */
  flags?: CommandFlag[];
  /** Non-empty lines from the cobra Example string. */
  examples?: string[];
  /**
   * True when this command can run inside the browser WASM build.
   * Derived from the kapi-wasm-cli buildRoot allowlist plus a curated
   * override map for commands that require network, the OS keychain,
   * SQLite (cgo), or a running server.
   */
  offlineCapable: boolean;
  /**
   * True when the command is present in the kapi-wasm-cli buildRoot and can
   * actually run in the browser playground — offline commands directly, AI/MT
   * commands via the demo provider. Gates the ▸ Run affordance.
   */
  runnableInBrowser: boolean;
  /**
   * True for commands that run in-browser only via the deterministic demo
   * provider (AI/MT). Their output is illustrative, not from a real model — the
   * UI labels these "Demo".
   */
  demoMode: boolean;
}

/** Top-level document for commands.json. */
export interface CommandDataset {
  generatedAt: string;
  commands: CommandEntry[];
}
